def get_evaluaciones(
    rama: str | None = None,
    tipo: str | None = None,
    nivel: str | None = None,
) -> list[dict]:
    """Filtra evaluaciones por rama, tipo y/o nivel."""
    result = EVALUACIONES
    if rama:
        result = [e for e in result if e["rama"] == rama]
    if tipo:
        result = [e for e in result if e["tipo"] == tipo]
    if nivel:
        result = [e for e in result if e["nivel"] == nivel]
    return result


RAMAS = sorted({e["rama"] for e in EVALUACIONES})
TIPOS = sorted({e["tipo"] for e in EVALUACIONES})
NIVELES = ["pregrado_basico", "pregrado_avanzado", "posgrado"]
